import type { ChipProps } from "tscircuit"

const pinLabels = {
  pin1: "GND",
  pin2: "TRIG",
  pin3: "OUT",
  pin4: "RESET",
  pin5: "CTRL",
  pin6: "THRES",
  pin7: "DISCH",
  pin8: "VCC",
} as const

export const NE555 = (props: ChipProps<typeof pinLabels>) => (
  <chip
    {...props}
    pinLabels={pinLabels}
    pinAttributes={{
      VCC: { requiresPower: true },
      RESET: { mustBeConnected: true },
    }}
