      leftSide: {
        direction: "top-to-bottom",
        pins: ["RESET", "CTRL", "THRES", "TRIG"],
      },
      rightSide: {
        direction: "top-to-bottom",
        pins: ["VCC", "OUT", "DISCH", "GND"],
      },
    }}
    supplierPartNumbers={{ jlcpcb: ["C46749"] }}
    footprint="dip8"
  />
)

export default () => (
